vector<int> earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
    vector<int> result;
    int firstPlayerIndex = firstPlayer - 1;
    int secondPlayerIndex = secondPlayer - 1;

    if (firstPlayerIndex > secondPlayerIndex) {
        swap(firstPlayerIndex, secondPlayerIndex);
    }

    int rounds = 0;
    while (firstPlayerIndex != secondPlayerIndex) {
        rounds++;
        result.push_back(rounds);
        if (firstPlayerIndex == secondPlayerIndex) {
            break;
        }
        swap(firstPlayerIndex, secondPlayerIndex);
    }

    result.push_back(rounds);

    return result;
}

